init_eqs:
n = 0;
loop (50000,
gmegabuf(n) = 0;
megabuf(n) = 0;
n = n+1;
);

sw1 = rand(8);
sw2 = rand(8);
sw3 = rand(8);
sw4 = rand(8);

frame_eqs:
flen = 512; //Wave Punkte
reg00 = FLen;
SLen = FLen/2;
dec_m = pow(.94, 30/fps);

//Volume
n = 0; vol = 0;
loop (SLen,
vol = vol + pow(gmegabuf(n),2)/FLen;
n = n+1;
);
vol = sqrt(vol)/2;
vol_ = vol_*dec_m + (1-dec_m)* (vol);

//switches
lev1 = lev1 * dec_m + (1-dec_m) * gmegabuf(1);
lev2 = lev2 * dec_m + (1-dec_m) * gmegabuf(20);
lev3 = lev3 * dec_m + (1-dec_m) * gmegabuf(50);
lev4 = lev4 * dec_m + (1-dec_m) * gmegabuf(100);
sw1 = sw1 + (lev1-gmegabuf(1)>0)/fps;
sw2 = sw2 + (lev2-gmegabuf(20)>0)/fps;
sw3 = sw3 + (lev3-gmegabuf(50)>0)/fps;
sw4 = sw4 + (lev4-gmegabuf(100)>0)/fps;

dif = (1+sin(sw3/4))*16+2;
ofs = sin(sw2/3)*8;
n = 0; k1 = frame*0;
loop (SLen,
m1 = (n)%SLen;
m2 = (n+ofs)%SLen;

k = (m1+dif)%SLen;
i = (SLen+m2-dif)%SLen;

in1 = (gmegabuf(m1)-gmegabuf(k))/pow(vol_+.03,.8)*1.2;
in2 = (gmegabuf(m2)-gmegabuf(i))/pow(vol_+.03,.8)*1.2;

dec = if (pow(gmegabuf(2000+n),2) + pow(gmegabuf(2000+FLen+n),2)> in1*in1+in2*in2,.8,.94) ;
dec = pow (dec, 30/fps);

gmegabuf(2000+n) =       gmegabuf(2000+n)*dec      +(1-dec)* in1;
gmegabuf(2000+FLen+n) =  gmegabuf(2000+FLen+n)*dec +(1-dec)* in2;
n=n+1;
);

q1 = (bass+treb+mid)/3;
q2 = (bass_att+treb_att+mid_att)/3;
q3 = vol_;
q11 = sw1;
q12 = sw2;
q13 = sw3;
q14 = sw4;

rot = 0; zoom = .98; warp = .3; rot = 0;

q32 = aspecty;
monitor = dif;

q15 = 0.18;

wave_0_per_point:
FLen = reg00;

n = int(sample*FLen);
vol = (value1+value2) * (1+ .1 / (sample+.03));

chg = min(max(vol- gmegabuf(n),-1),1);
dec = if (chg>0, 1-chg*0.3, 1+chg*0.2);

chg = q1 -q2;
dec = .94 - abs(chg) * if (chg> 0, .2,.1);

dec = min(max(dec,0),1);
gmegabuf(n) = gmegabuf(n)*dec + vol*(1-dec);

dec = q2/4;
//dec = .90;
dec = max(min(dec,1),.1);

gmegabuf(n) = gmegabuf(n)*dec + gmegabuf(n+(q2<.8))*(1-dec);
gmegabuf(n+10000) = gmegabuf(n+10000)*.2 + .8* vol/3;
a = .0;
x = sample;
y = .2 + gmegabuf(n+0)*.23;

shape_1_per_frame:
n = (instance);
FLen = reg00;
SLen = reg00/2;

z0 = 10;
y0 = gmegabuf(2000+n+FLen)/z0;
x0 = gmegabuf(2000+n)/z0;

a0 = (gmegabuf(n+10000));

k1 = instance/num_inst-.5;
x = .5 + x0 + sin(k1*8*sin(q12*.07)) * sin(q11*.13)*q3*.7;
y = .5 + q32*(y0 + sin(k1*8*sin(q14*.1)) * sin(q13*.2)*q3*.7);

arg = q2/8;
high = exp(-500*pow(arg+.5-instance/num_inst,2));
high += exp(-500*pow(-arg+.5-instance/num_inst,2));

exc = sqrt((pow(x-.5,2)+pow(y-.5,2)));
rad0 = above(z0,0)*min (.1, a0/60)+.005;
rad0 = rad0 * (1+2*exc) * (1+high);

p1 = .5 + sin(q12)/2;
p2 = .5 + sin(q13*1.4)/2;
//p1 = rand(1)-.5;
//p2 = rand(1)-.5;
exc = ((pow(x-p1,2)+pow(y-p2,2)));
rad = min(rad0 * (1 + .004*q3/abs(exc)),1) ;

a = min(a0*8+.4,1);

k1 = instance/num_inst*5 + high;
w = 1-exp(-treb_att/2-.5);
g = w + (1-w)*sin(k1);
r = w + (1-w)*sin(k1-6.28/3);
b = w + (1-w)*sin(k1-6.28*2/3);

a2 = a/4;
g2 = g*0; b2 = b*0; r2 = r*0;

